#include <bits/stdc++.h>using namespace std;typedef long long ll; int main() {    ll t;    cin >> t;    while(t--){        ll n, m;        cin >> n >> m;        vector<vector<ll>> adj(n);        for(ll i = 0; i < m; i++){            ll u, v;            cin >> u >> v;            u--; v--;            adj[u].push_back(v);            adj[v].push_back(u);        }        vector<ll> color(n, -1);        ll ans = 0;        for(ll i = 0; i < n; i++){            queue<ll> q;            if(color[i] == -1){                q.push(i);                color[i] = 0;                ll cnt1=0, cnt2=0;                bool isBipartite = true;                while(!q.empty()){                    ll u = q.front();                    q.pop();                    if(color[u] == 0) cnt1++;                    else cnt2++;                    for(ll v : adj[u]){                        if(color[v] == -1){                            color[v] = 1 - color[u];                            q.push(v);                        } else if(color[v] == color[u]){                            isBipartite = false;                        }                    }                }                if(isBipartite){                    ans += max(cnt1, cnt2);                }            }        }        cout<<ans<<endl;    }}